package org.eclipse.rdf4j.query.algebra.evaluation.sketch.omni;

import static java.lang.foreign.ValueLayout.JAVA_BYTE;

import java.lang.foreign.MemorySegment;

import org.apache.datasketches.common.MemorySegmentStatus;
import org.apache.datasketches.common.SketchesArgumentException;

/** Read-only compact OmniSketch backed by a caller-owned MemorySegment. */
final class WrappedCompactOmniSketch extends CompactOmniSketch {
	private final MemorySegment seg;
	private final int lgWidth;
	private final int numRows;
	private final int nominalEntries;
	private final long seed;
	private final long totalUpdates;
	private final int retainedEntries;
	private final int compactBytes;

	WrappedCompactOmniSketch(final MemorySegment seg) {
		this.seg = seg;
		PreambleUtil.checkPreamble(seg);
		lgWidth = PreambleUtil.extractLgWidth(seg);
		numRows = PreambleUtil.extractNumRows(seg);
		nominalEntries = PreambleUtil.extractNominalEntries(seg);
		seed = PreambleUtil.extractSeed(seg);
		totalUpdates = PreambleUtil.extractTotalUpdates(seg);
		retainedEntries = PreambleUtil.extractRetainedEntries(seg);
		compactBytes = PreambleUtil.extractSerializationBytes(seg);
	}

	@Override
	public int getLgWidth() {
		return lgWidth;
	}

	@Override
	public int getNumRows() {
		return numRows;
	}

	@Override
	public int getNominalEntries() {
		return nominalEntries;
	}

	@Override
	public long getSeed() {
		return seed;
	}

	@Override
	public long getTotalUpdates() {
		return totalUpdates;
	}

	@Override
	public int getRetainedEntries() {
		return retainedEntries;
	}

	@Override
	public boolean isEmpty() {
		return PreambleUtil.isEmpty(seg) || totalUpdates == 0L;
	}

	@Override
	public boolean hasMemorySegment() {
		return seg != null && seg.scope().isAlive();
	}

	@Override
	public boolean isOffHeap() {
		return hasMemorySegment() && seg.isNative();
	}

	@Override
	public boolean isSameResource(final MemorySegment that) {
		return hasMemorySegment() && MemorySegmentStatus.isSameResource(seg, that);
	}

	@Override
	public OmniSketchEstimate estimate(final OmniSketchPredicate predicate) {
		return summary(predicate).asEstimate();
	}

	@Override
	public CompactOmniSketch compact(final MemorySegment dstSeg) {
		if (dstSeg == null) {
			return this;
		}
		if (dstSeg.byteSize() < compactBytes) {
			throw new SketchesArgumentException("Destination MemorySegment is too small for compact OmniSketch: "
					+ dstSeg.byteSize() + " < " + compactBytes);
		}
		final byte[] bytes = toByteArray();
		for (int i = 0; i < bytes.length; i++) {
			dstSeg.set(JAVA_BYTE, i, bytes[i]);
		}
		return CompactOmniSketch.wrap(dstSeg.asSlice(0, compactBytes));
	}

	@Override
	public byte[] toByteArray() {
		final byte[] out = new byte[compactBytes];
		MemorySegment.copy(seg, JAVA_BYTE, 0, out, 0, compactBytes);
		return out;
	}

	@Override
	public int getCompactBytes() {
		return compactBytes;
	}

	@Override
	OmniSketchCell getCell(final int row, final int column) {
		return OmniSketchSerializationUtil.readCell(seg, row, column);
	}

	@Override
	public String toString() {
		return "WrappedCompactOmniSketch{" + "lgWidth=" + lgWidth + ", numRows=" + numRows + ", nominalEntries="
				+ nominalEntries + ", totalUpdates=" + totalUpdates + ", retainedEntries=" + retainedEntries + '}';
	}
}
